UPDATE `quest_template` SET `entry`=365, `Method`=2, `ZoneOrSort`=85, `MinLevel`=4, `MaxLevel`=255, `QuestLevel`=7, `Type`=0, `RequiredClasses`=0, `RequiredRaces`=178, `RequiredSkill`=0, `RequiredSkillValue`=0, `RequiredCondition`=0, `RepObjectiveFaction`=0, `RepObjectiveValue`=0, `RequiredMinRepFaction`=0, `RequiredMinRepValue`=0, `RequiredMaxRepFaction`=0, `RequiredMaxRepValue`=0, `SuggestedPlayers`=0, `LimitTime`=0, `QuestFlags`=8, `SpecialFlags`=0, `PrevQuestId`=0, `NextQuestId`=0, `ExclusiveGroup`=0, `BreadcrumbForQuestId`=0, `NextQuestInChain`=407, `SrcItemId`=0, `SrcItemCount`=0, `SrcSpell`=0, `Title`='Fields of Grief', `Details`='What have we here?  You look like a fledgling $c.  If you hope to prove yourself to The Dark Lady, you need to learn the ways of The Forsaken.$B$BTo the west you\'ll find a farm.  Humans infest the land like mold on a rotting corpse.  And worse yet, the Scarlet Crusade patrols nearby from their tower.  Teach those scum a lesson and steal 10 of their precious pumpkins.$B$BOnce you have 10, take them to Apothecary Johaan in Brill.', `Objectives`='Steal 10 pumpkins from the farm to the west, just north of Deathknell and take them to Apothecary Johaan in Brill.', `OfferRewardText`='You have performed your bidding well, young $C. You are proving yourself to be quite an asset to The Dark Lady\'s army.$B$BTake this harvest satchel. Even the smallest servant of the Banshee Queen must learn to carry their burdens well.', `RequestItemsText`='Deathguard Simmer sent word that you were going to provide me with some much needed reagents. Were you able to gather 10 pumpkins yet, $N?', `EndText`='', `ObjectiveText1`='', `ObjectiveText2`='', `ObjectiveText3`='', `ObjectiveText4`='', `ReqItemId1`=2846, `ReqItemId2`=0, `ReqItemId3`=0, `ReqItemId4`=0, `ReqItemCount1`=10, `ReqItemCount2`=0, `ReqItemCount3`=0, `ReqItemCount4`=0, `ReqSourceId1`=0, `ReqSourceId2`=0, `ReqSourceId3`=0, `ReqSourceId4`=0, `ReqSourceCount1`=0, `ReqSourceCount2`=0, `ReqSourceCou